// 1. Sadə funksiya tipi
function add(a: number, b: number): number {
  return a + b;
}
console.log(add(5, 3)); // Çıxış: 8
// console.log(add("5", 3)); // Xəta: string number tipinə uyğun deyil

// 2. Arrow funksiya tipi
const multiply: (a: number, b: number) => number = (a, b) => a * b;
console.log(multiply(4, 2)); // Çıxış: 8

// 3. Interface ilə funksiya tipi
interface Calculator {
  (x: number, y: number): number;
}
const subtract: Calculator = (x, y) => x - y;
console.log(subtract(10, 4)); // Çıxış: 6

// 4. Type ilə funksiya tipi
type Greet = (name: string, greeting?: string) => string;
const sayHello: Greet = (name, greeting = "Hello") => `${greeting}, ${name}!`;
console.log(sayHello("Murad")); // Çıxış: Hello, Murad!
console.log(sayHello("Alice", "Hi")); // Çıxış: Hi, Alice!

// 5. Opsiyonel parametrlər
type LogMessage = (message: string, level?: "info" | "error") => void;
const log: LogMessage = (message, level = "info") => {
  console.log(`[${level.toUpperCase()}] ${message}`);
};
log("System started"); // Çıxış: [INFO] System started
log("Error occurred", "error"); // Çıxış: [ERROR] Error occurred

// 6. Metod tipləri ilə interface
interface Product {
  name: string;
  price: number;
  getDescription: () => string;
}
const laptop: Product = {
  name: "Laptop",
  price: 1200,
  getDescription() {
    return `${this.name}: $${this.price}`;
  }
};
console.log(laptop.getDescription()); // Çıxış: Laptop: $1200

// Sadə mağaza sistemi
interface Product {
  name: string;
  price: number;
}

type DiscountFunction = (product: Product, discount?: number) => number;
const applyDiscount: DiscountFunction = (product, discount = 0) => {
  return product.price * (1 - discount / 100);
};

const laptop: Product = { name: "Laptop", price: 1200 };
console.log(applyDiscount(laptop)); // Çıxış: 1200 (endirim yoxdur)
console.log(applyDiscount(laptop, 10)); // Çıxış: 1080 (10% endirim)

// Funksiya metod kimi
interface Cart {
  items: Product[];
  getTotal: () => number;
}
const cart: Cart = {
  items: [{ name: "Mouse", price: 25 }, { name: "Keyboard", price: 50 }],
  getTotal() {
    return this.items.reduce((sum, item) => sum + item.price, 0);
  }
};
console.log(cart.getTotal()); // Çıxış: 75

